{"code": "import json
import statistics

# Get the review data from the previous query
reviews = locals()['var_functions.query_db:8']

# Group ratings by gmap_id
business_ratings = {}
for review in reviews:
    gmap_id = review['gmap_id']
    rating = int(review['rating'])

    if gmap_id not in business_ratings:
        business_ratings[gmap_id] = []
    business_ratings[gmap_id].append(rating)

# Calculate average rating for each business
avg_ratings = {}
for gmap_id, ratings in business_ratings.items():
    avg_ratings[gmap_id] = statistics.mean(ratings)

# Filter businesses with average rating >= 4.0
high_rated_businesses = {gmap_id: avg for gmap_id, avg in avg_ratings.items() if avg >= 4.0}

# Get business names for these gmap_ids
business_data = locals()['var_functions.query_db:5']
business_names = {b['gmap_id']: b['name'] for b in business_data}

# Prepare final results
results = []
for gmap_id, avg_rating in high_rated_businesses.items():
    if gmap_id in business_names:
        results.append({
            'business_name': business_names[gmap_id],
            'average_rating': round(avg_rating, 2)
        })

# Sort by rating (highest first)
results = sorted(results, key=lambda x: x['average_rating'], reverse=True)

print('__RESULT__:')
print(json.dumps(results))"}
